arguments.new_str:
class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 behavioral change: empty env vars are no longer treated as unset.
        // GetEnvironmentVariable now returns "" (instead of null) for empty vars.
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val == null)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
        else if (val.Length == 0)
        {
            Console.WriteLine("MY_FLAG explicitly empty");
        }
    }
}

